import base64
import pickle
import logging

def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Decodes a Base64-encoded string from a cookie and restores the user's
    preference settings.

    Args:
        encoded_prefs: A Base64-encoded string containing pickled data.

    Returns:
        A dictionary representing the user's preferences. Returns an empty
        dictionary if decoding or parsing fails.
    """
    if not encoded_prefs:
        logging.warning("Empty cookie string provided.")
        return {}

    try:
        # Decode the Base64 string to bytes
        decoded_bytes = base64.b64decode(encoded_prefs)

        # Deserialize the bytes using pickle
        preferences = pickle.loads(decoded_bytes)

        # Ensure the returned value is a dictionary, as expected
        if isinstance(preferences, dict):
            return preferences
        else:
            logging.warning(f"Decoded preferences are not a dictionary: {type(preferences)}")
            return {}

    except Exception as e:
        logging.error(f"Failed to decode or parse preferences: {e}")
        return {}

