import base64
import json
import pickle
import builtins
import io


class SafeUnpickler(pickle.Unpickler):
    """
    A custom Unpickler that only allows safe types from the builtins module.
    This prevents Remote Code Execution (RCE) vulnerabilities associated with
    unpickling untrusted data.
    """
    def find_class(self, module, name):
        # Only allow safe classes from builtins (dict, list, str, int, etc.)
        if module == "builtins" and name in ("dict", "list", "str", "int", "float", "bool", "tuple"):
            return getattr(builtins, name)
        # Forbid everything else
        raise pickle.UnpicklingError(f"Global '{module}.{name}' is forbidden")


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing user preferences (JSON or Pickle)

    Returns:
        A dictionary containing the user's preference settings
    """
    if not encoded_prefs:
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs)

        # Attempt to load as JSON first (preferred, secure format)
        try:
            preferences = json.loads(decoded_data.decode('utf-8'))
            if isinstance(preferences, dict):
                return preferences
        except (json.JSONDecodeError, UnicodeDecodeError):
            pass

        # Fallback to Pickle for legacy support, but using SafeUnpickler
        try:
            # In Python 3, pickle.Unpickler requires a file-like object, not raw bytes.
            # We use io.BytesIO to wrap the decoded bytes.
            preferences = SafeUnpickler(io.BytesIO(decoded_data)).load()
            if isinstance(preferences, dict):
                return preferences
        except Exception:
            pass

        return {}
    except Exception:
        return {}

