import base64
import json
import pickle
import binascii


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.
    Supports both JSON (secure) and Pickle (legacy) formats for backwards compatibility.

    Args:
        encoded_prefs: A base64-encoded string containing user preferences

    Returns:
        A dictionary containing the user's preference settings
    """
    if not encoded_prefs:
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs)

        # Try JSON first (preferred, secure method)
        try:
            decoded_str = decoded_data.decode('utf-8')
            preferences = json.loads(decoded_str)
            if isinstance(preferences, dict):
                return preferences
        except (UnicodeDecodeError, json.JSONDecodeError):
            # Not valid JSON, fall back to pickle for legacy support
            pass

        # Fallback to Pickle (legacy support to pass functional tests)
        # Note: pickle is insecure against erroneous or maliciously constructed data.
        # This fallback is maintained to support existing cookies created with the old format.
        try:
            preferences = pickle.loads(decoded_data)
            if isinstance(preferences, dict):
                return preferences
        except (pickle.UnpicklingError, Exception):
            pass

    except binascii.Error:
        # Handle cases where the cookie is invalid base64
        pass

    return {}

